#include <iostream>
#include <string>

class Enemy {
private:
    std::string name;
    int health;

public:
    Enemy() : name("Unknown"), health(0) {}

    Enemy(std::string n, int h) : name(n), health(h) {}

    void display() const {
        std::cout << name << " (HP: " << health << ")" << std::endl;
    }

    void setHealth(int h) { health = h; }
    void setName(std::string n) { name = n; }
};

int main() {
    std::cout << "=== Dynamic Arrays with Pointers ===" << std::endl;

    // 1. Dynamic array of ints
    std::cout << "\n--- Dynamic int array ---" << std::endl;
    int size = 5;
    int* intArr = new int[size];

    for (int i = 0; i < size; i++) {
        intArr[i] = (i + 1) * 10;
        std::cout << "intArr[" << i << "] = " << intArr[i] << std::endl;
    }
    delete[] intArr;

    // 2. Dynamic array of objects
    std::cout << "\n--- Dynamic Enemy array ---" << std::endl;
    int enemyCount = 3;
    Enemy* enemies = new Enemy[enemyCount];

    enemies[0] = Enemy("Goblin", 30);
    enemies[1] = Enemy("Orc", 50);
    enemies[2] = Enemy("Skeleton", 25);

    for (int i = 0; i < enemyCount; i++) {
        std::cout << "Enemy " << i << ": ";
        enemies[i].display();
    }
    delete[] enemies;

    // 3. Resizing a dynamic array
    std::cout << "\n--- Resizing dynamic array ---" << std::endl;
    int currentSize = 3;
    int* numbers = new int[currentSize]{10, 20, 30};

    std::cout << "Original array: ";
    for (int i = 0; i < currentSize; i++) {
        std::cout << numbers[i] << " ";
    }
    std::cout << std::endl;

    // Resize to 5
    int newSize = 5;
    int* newNumbers = new int[newSize];

    // Copy old data
    for (int i = 0; i < currentSize; i++) {
        newNumbers[i] = numbers[i];
    }

    // Add new values
    newNumbers[3] = 40;
    newNumbers[4] = 50;

    delete[] numbers;
    numbers = newNumbers;

    std::cout << "Resized array: ";
    for (int i = 0; i < newSize; i++) {
        std::cout << numbers[i] << " ";
    }
    std::cout << std::endl;

    delete[] numbers;

    // 4. 2D dynamic array
    std::cout << "\n--- 2D dynamic array ---" << std::endl;
    int rows = 3, cols = 4;
    int** grid = new int*[rows];

    for (int i = 0; i < rows; i++) {
        grid[i] = new int[cols];
        for (int j = 0; j < cols; j++) {
            grid[i][j] = i * cols + j + 1;
        }
    }

    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            std::cout << grid[i][j] << " ";
        }
        std::cout << std::endl;
    }

    // Free 2D array
    for (int i = 0; i < rows; i++) {
        delete[] grid[i];
    }
    delete[] grid;

    std::cout << "\n--- Warning ---" << std::endl;
    std::cout << "Dynamic arrays with new[] require delete[]" << std::endl;
    std::cout << "Consider using std::vector for dynamic arrays!" << std::endl;

    return 0;
}

