#include <iostream>
#include <string>

struct Enemy {
    std::string name;
    int health;
};

int main() {
    int count;
    std::cout << "How many enemies? ";
    std::cin >> count;

    Enemy* enemies = new Enemy[count];
    for (int i = 0; i < count; i++) {
        enemies[i].name = "Enemy " + std::to_string(i + 1);
        enemies[i].health = 50 + i * 10;
    }

    std::cout << "\n=== Enemies ===" << std::endl;
    for (int i = 0; i < count; i++) {
        std::cout << enemies[i].name << " (HP: " << enemies[i].health << ")" << std::endl;
    }
    delete[] enemies;

    std::cout << "\n=== 2D Grid ===" << std::endl;
    int rows = 3, cols = 3;
    int** grid = new int*[rows];
    for (int i = 0; i < rows; i++) {
        grid[i] = new int[cols];
        for (int j = 0; j < cols; j++) {
            grid[i][j] = i * cols + j + 1;
        }
    }

    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            std::cout << grid[i][j] << " ";
        }
        std::cout << std::endl;
    }

    for (int i = 0; i < rows; i++) {
        delete[] grid[i];
    }
    delete[] grid;

    return 0;
}
